// Get transcript from WayinVideo
const segments = $('4. WayinVideo — Get Transcript Results').item.json.data.transcript || [];

if (segments.length === 0) {
  throw new Error('Transcript is empty — check if the recording URL is valid and publicly accessible.');
}

// Format transcript with speaker labels and timestamps
const formattedTranscript = segments
  .map(s => {
    const timeInSeconds = Math.floor(s.start / 1000);
    const minutes = Math.floor(timeInSeconds / 60);
    const seconds = timeInSeconds % 60;
    const timestamp = `${minutes}:${seconds.toString().padStart(2, '0')}`;
    return `[${s.speaker} | ${timestamp}] ${s.text.trim()}`;
  })
  .join('\n');

// Duration
const lastSegment = segments[segments.length - 1];
const totalDurationMs = lastSegment?.end || 0;
const totalMinutes = Math.round(totalDurationMs / 60000);

// Speakers
const speakers = [...new Set(segments.map(s => s.speaker))];

return [{
  json: {
    formattedTranscript,
    totalMinutes,
    speakerCount: speakers.length,
    speakers: speakers.join(', '),
    contactEmail: $('1. Form — Call Recording + CRM Details').item.json['Contact Email'],
    contactName: $('1. Form — Call Recording + CRM Details').item.json['Contact Name'],
    companyName: $('1. Form — Call Recording + CRM Details').item.json['Company Name'],
    callPurpose: $('1. Form — Call Recording + CRM Details').item.json['Call Purpose'],
    callDate: $('1. Form — Call Recording + CRM Details').item.json['Call Date'],
    salesRep: $('1. Form — Call Recording + CRM Details').item.json['Sales Rep Name'],
    recordingUrl: $('1. Form — Call Recording + CRM Details').item.json['Call Recording URL']
  }
}];

// Parse AI output into structured CRM fields
const output = $input.first().json.output || '';

// Extract each section
const callSummaryMatch = output.match(/CALL_SUMMARY:\s*([\s\S]*?)(?=\nPAIN_POINTS:|$)/);
const painPointsMatch = output.match(/PAIN_POINTS:\s*([\s\S]*?)(?=\nOBJECTIONS_RAISED:|$)/);
const objectionsMatch = output.match(/OBJECTIONS_RAISED:\s*([\s\S]*?)(?=\nKEY_QUOTES:|$)/);
const keyQuotesMatch = output.match(/KEY_QUOTES:\s*([\s\S]*?)(?=\nNEXT_STEPS:|$)/);
const nextStepsMatch = output.match(/NEXT_STEPS:\s*([\s\S]*?)(?=\nFOLLOW_UP_DATE:|$)/);
const followUpMatch = output.match(/FOLLOW_UP_DATE:\s*([\s\S]*?)(?=\nDEAL_STAGE:|$)/);
const dealStageMatch = output.match(/DEAL_STAGE:\s*([\s\S]*?)(?=\nSENTIMENT:|$)/);
const sentimentMatch = output.match(/SENTIMENT:\s*([\s\S]*?)(?=\nCONFIDENCE_SCORE:|$)/);
const confidenceMatch = output.match(/CONFIDENCE_SCORE:\s*([\s\S]*)$/);

const callSummary = callSummaryMatch ? callSummaryMatch[1].trim() : '';
const painPoints = painPointsMatch ? painPointsMatch[1].trim() : '';
const objections = objectionsMatch ? objectionsMatch[1].trim() : '';
const keyQuotes = keyQuotesMatch ? keyQuotesMatch[1].trim() : '';
const nextSteps = nextStepsMatch ? nextStepsMatch[1].trim() : '';
const followUpDate = followUpMatch ? followUpMatch[1].trim() : 'TBD';
const dealStage = dealStageMatch ? dealStageMatch[1].trim() : 'Qualification';
const sentiment = sentimentMatch ? sentimentMatch[1].trim() : 'Neutral';
const confidenceScore = confidenceMatch ? confidenceMatch[1].trim() : '5';

// Build full HubSpot note body
const noteBody = [
  `CALL NOTE — ${$('7. Code — Format Transcript').item.json.callPurpose}`,
  `Date: ${$('7. Code — Format Transcript').item.json.callDate} | Duration: ${$('7. Code — Format Transcript').item.json.totalMinutes} min | Rep: ${$('7. Code — Format Transcript').item.json.salesRep}`,
  `Recording: ${$('7. Code — Format Transcript').item.json.recordingUrl}`,
  ``,
  `SUMMARY`,
  callSummary,
  ``,
  `PAIN POINTS`,
  painPoints,
  ``,
  `OBJECTIONS`,
  objections,
  ``,
  `KEY QUOTES`,
  keyQuotes,
  ``,
  `NEXT STEPS`,
  nextSteps,
  ``,
  `DEAL INTELLIGENCE`,
  `Stage: ${dealStage} | Sentiment: ${sentiment} | Confidence: ${confidenceScore}/10`,
  `Follow-up: ${followUpDate}`
].join('\n');

// Calculate follow-up timestamp for HubSpot task (7 days from now if TBD)
const followUpTimestamp = followUpDate !== 'TBD'
  ? new Date(followUpDate).getTime()
  : Date.now() + (7 * 24 * 60 * 60 * 1000);

return [{
  json: {
    callSummary,
    painPoints,
    objections,
    keyQuotes,
    nextSteps,
    followUpDate,
    dealStage,
    sentiment,
    confidenceScore,
    noteBody,
    followUpTimestamp,
    contactEmail: $('7. Code — Format Transcript').item.json.contactEmail,
    contactName: $('7. Code — Format Transcript').item.json.contactName,
    companyName: $('7. Code — Format Transcript').item.json.companyName,
    callPurpose: $('7. Code — Format Transcript').item.json.callPurpose,
    callDate: $('7. Code — Format Transcript').item.json.callDate,
    salesRep: $('7. Code — Format Transcript').item.json.salesRep,
    recordingUrl: $('7. Code — Format Transcript').item.json.recordingUrl,
    totalMinutes: $('7. Code — Format Transcript').item.json.totalMinutes
  }
}];

// Extract HubSpot contact ID from search results
const results = $json.results || [];

if (results.length === 0) {
  throw new Error(`Contact not found in HubSpot for email: ${$('10. Code — Parse CRM Output').item.json.contactEmail}. Please add the contact to HubSpot first.`);
}

const contact = results[0];
const contactId = contact.id;

// Pass through all CRM data with contact ID added
const crmData = $('10. Code — Parse CRM Output').item.json;

return [{
  json: {
    ...crmData,
    hubspotContactId: contactId
  }
}];

